html:
{% set is_gift = frappe.form_dict.gift or False %}
<style>
    @page { size: 80mm auto; margin: 0mm; }
    body {
        font-family: 'Courier New', Courier, monospace;
        font-size: 8.5px; line-height: 1.2;
        color: #000; background: #fff;
        width: 74mm; margin: 0; padding: 1.5mm 3mm;
        box-sizing: border-box;
    }
    .center { text-align: center; }
    .right { text-align: right; }
    .bold { font-weight: bold; }
    .legal { font-size: 6.5px; line-height: 1.15; }
    hr { border: none; border-top: 0.5px solid #000; margin: 2px 0; }
    hr.dash { border-top: 0.5px dashed #999; }
    .header-info { width: 100%; font-size: 8px; line-height: 1.2; margin: 1px 0; }
    .header-info td { vertical-align: top; padding: 0; }
    table.items { width: 100%; border-collapse: collapse; font-size: 7.5px; margin: 1px 0; }
    table.items th {
        font-size: 7px; border-bottom: 0.5px solid #000;
        padding: 1px 0; white-space: nowrap;
    }
    table.items td { padding: 0.5px 0; vertical-align: top; }
    .item-desc { font-size: 7.5px; line-height: 1.15; }
    .item-ref { font-size: 6.5px; color: #555; }
    table.totals { width: 100%; border-collapse: collapse; font-size: 8px; margin: 1px 0; }
    table.totals td { padding: 0.5px 0; }
    .grand-total { font-size: 11px; font-weight: bold; }
    table.payments { width: 100%; border-collapse: collapse; font-size: 7.5px; margin: 1px 0; }
    .barcode-section { text-align: center; margin-top: 8px; padding-top: 4px; }
    .barcode-section img { max-width: 90%; height: 36px; }
    .barcode-section .ticket-id { font-size: 7px; color: #555; margin-top: 1px; }
</style>

{% if is_gift %}
<div class="center" style="font-size:12px;font-weight:bold;margin-bottom:4px;letter-spacing:2px;">
    TICKET REGALO
</div>
<hr>
{% endif %}

{{ letter_head }}

<table class="header-info">
    <tr>
        <td width="50%"><strong>N&ordm;:</strong> {{ doc.name }}</td>
        <td class="right"><strong>Fecha:</strong> {{ doc.get_formatted("posting_date") }}</td>
    </tr>
    <tr>
        <td><strong>Hora:</strong> {{ doc.posting_time }}</td>
        <td class="right">{% if not is_gift %}Factura simplificada{% endif %}</td>
    </tr>
    <tr>
        <td colspan="2"><strong>Cajero:</strong> {{ doc.owner }}</td>
    </tr>
</table>
<hr class="dash">

<table class="items">
    <thead>
        <tr>
            <th width="16">Ud.</th>
            <th width="48">EAN</th>
            <th>Descripci&oacute;n</th>
            {% if not is_gift %}
            <th width="42" class="right">Precio</th>
            <th width="42" class="right">Importe</th>
            {% endif %}
        </tr>
    </thead>
    <tbody>
    {% for item in doc.items %}
        {% set ean = item.barcode or frappe.db.get_value("Item Barcode", {"parent": item.item_code}, "barcode") or item.item_code[:12] %}
        <tr>
            <td class="bold">{{ item.qty|int }}</td>
            <td class="item-ref">{{ ean }}</td>
            <td class="item-desc">{{ item.item_name[:32] }}</td>
            {% if not is_gift %}
            <td class="right">
                {{ frappe.utils.fmt_money(item.rate|float, currency=None) }}&nbsp;&euro;
                {%- if item.discount_percentage %}
                <br><span style="font-size:6.5px;color:#888;">-{{ item.discount_percentage|int }}%</span>
                {% endif %}
            </td>
            <td class="right">
                <span class="bold">{{ frappe.utils.fmt_money(item.amount|float, currency=None) }}&nbsp;&euro;</span>
            </td>
            {% endif %}
        </tr>
        {% if item.item_code not in (ean or '') %}
        <tr><td colspan="2" class="item-ref">Ref: {{ item.item_code }}</td><td colspan="{% if is_gift %}1{% else %}3{% endif %}"></td></tr>
        {% endif %}
    {% endfor %}
    </tbody>
</table>
<hr>

{% if not is_gift %}
<table class="totals">
    <tr>
        <td>Base Imponible</td>
        <td class="right">{{ frappe.utils.fmt_money(doc.net_total|float, currency=None) }}&nbsp;&euro;</td>
    </tr>
    {% for tax in doc.taxes %}
    {% set tax_amt = tax.tax_amount|float %}
    {% if tax_amt > 0 %}
    <tr>
        <td>
            {%- if tax.rate is defined and tax.rate|float > 0 -%}
                {{ tax.description or tax.account_head }} ({{ tax.rate|int if tax.rate == tax.rate|int else tax.rate }}%)
            {%- else -%}
                {{ tax.description or tax.account_head }}
            {%- endif -%}
        </td>
        <td class="right">{{ frappe.utils.fmt_money(tax_amt, currency=None) }}&nbsp;&euro;</td>
    </tr>
    {% endif %}
    {% endfor %}
    <tr><td colspan="2"><hr class="dash"></td></tr>
    <tr class="grand-total">
        <td>TOTAL{% if doc.taxes %} (IVA incl.){% endif %}</td>
        <td class="right">{{ frappe.utils.fmt_money(doc.grand_total|float, currency=None) }}&nbsp;&euro;</td>
    </tr>
</table>
<hr>

{% if doc.payments %}
<table class="payments">
    <tr><td colspan="2" class="bold">Forma de pago:</td></tr>
    {% for p in doc.payments %}
    {% set p_amt = p.amount|float %}
    {% if p_amt > 0 %}
    <tr>
        <td>{{ p.mode_of_payment }}</td>
        <td class="right">{{ frappe.utils.fmt_money(p_amt, currency=None) }}&nbsp;&euro;</td>
    </tr>
    {% endif %}
    {% endfor %}
</table>
<hr class="dash">
{% endif %}

{% endif %}

<div class="legal">
    {{ doc.terms or "" }}
    <p>Conserve el ticket para cualquier cambio o devoluci&oacute;n.<br>
    Los art&iacute;culos deben presentarse sin usar y con su embalaje original.</p>
</div>

<div class="barcode-section">
    <hr class="dash">
    <img src="https://barcode.tec-it.com/barcode.ashx?data={{ doc.name }}&code=Code39&translate-esc=true&dpi=72"
         alt="{{ doc.name }}">
    <div class="ticket-id">{{ doc.name }}</div>
</div>

